import React, { useState, useEffect } from "react";
import axios from "axios";

function App() {
    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");

    const handleLogin = async () => {
        try {
            const res = await axios.post("http://localhost:8080/auth/login", {
                username,
                password
            });

            localStorage.setItem("token", res.data);
            alert("Login successful!");

            window.location.reload(); // reload to apply token
        } catch (err) {
            console.error(err);
            alert("Login failed");
        }
    };
    const [file, setFile] = useState(null);
    const [result, setResult] = useState([]);

    const token = localStorage.getItem("token"); // ✅ get token


    useEffect(() => {
        if (!token) {
            console.warn("No token found. Please login first.");
            return;
        }

        axios.get("http://localhost:8080/resumes/test", {
            headers: {
                Authorization: `Bearer ${token}`
            }
        })
            .then(res => console.log("TEST API:", res.data))
            .catch(err => console.error("TEST ERROR:", err));
    }, [token]);

    const handleUpload = async () => {
        const formData = new FormData();
        formData.append("file", file);
        formData.append("name", "Test User");
        formData.append("email", "test@gmail.com");
        formData.append("skills", "java spring boot");
        formData.append("experience", 2);

        await axios.post(
            "http://localhost:8080/resumes/upload",
            formData,
            {
                headers: {
                    Authorization: `Bearer ${token}`, // ✅ FIX
                    "Content-Type": "multipart/form-data"
                }
            }
        );

        alert("Uploaded!");
    };

    const getMatches = async () => {
        const res = await axios.get(
            "http://localhost:8080/resumes/match?skill=java&experience=1",
            {
                headers: {
                    Authorization: `Bearer ${token}` // ✅ FIX
                }
            }
        );

        setResult(res.data);
    };
    if (!token){

    return (
        <div style={{ padding: 20 }}>
            <h2>TalentMatch AI</h2>

            <input type="file" onChange={(e) => setFile(e.target.files[0])} />
            <br /><br />
            <button onClick={handleUpload}>Upload Resume</button>

            <br /><br />
            <h3>Login</h3>

            <input
                placeholder="Username"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
            />

            <br /><br />

            <input
                type="password"
                placeholder="Password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
            />

            <br /><br />

            <button onClick={handleLogin}>Login</button>
        </div> );}
    return( <div style={{ padding: 20 }}>
            <h2>TalentMatch AI</h2>

            <button onClick={() => {
                localStorage.removeItem("token");
                window.location.reload();
            }}>
                Logout
            </button>

            <br /><br />

            <input type="file" onChange={(e) => setFile(e.target.files[0])} />
            <br /><br />

            <button onClick={handleUpload}>Upload Resume</button>

            <br /><br />

            <button onClick={getMatches}>Find Matches</button>

            <ul>
                {result?.map((r, i) => (
                    <li key={i}>
                        {r?.summary?.name || "No Name"} - Score: {r?.score}
                    </li>
                ))}
            </ul>
        </div>
    );
}

export default App;
